"""Central user-facing message catalog and localized error guidance.

The catalog uses stable keys so dialog text, common status messages, and
expected command-line/tool failures can be translated from one compatibility
layer instead of being embedded directly at every call site.
"""

from __future__ import annotations

from dataclasses import dataclass


DEFAULT_LANGUAGE = "en"


@dataclass(frozen=True)
class LanguageOption:
    code: str
    english_name: str
    native_name: str


SUPPORTED_LANGUAGES = (
    LanguageOption("en", "English", "English"),
    LanguageOption("es", "Spanish", "Español"),
    LanguageOption("fr", "French", "Français"),
    LanguageOption("de", "German", "Deutsch"),
    LanguageOption("it", "Italian", "Italiano"),
    LanguageOption("pt-BR", "Portuguese (Brazil)", "Português (Brasil)"),
    LanguageOption("nl", "Dutch", "Nederlands"),
    LanguageOption("pl", "Polish", "Polski"),
    LanguageOption("ja", "Japanese", "日本語"),
    LanguageOption("ko", "Korean", "한국어"),
    LanguageOption("zh-Hans", "Chinese (Simplified)", "简体中文"),
)

_SUPPORTED_CODES = {language.code for language in SUPPORTED_LANGUAGES}


def language_options():
    return SUPPORTED_LANGUAGES


def normalize_language_code(value):
    text = str(value or DEFAULT_LANGUAGE).strip()
    if not text:
        return DEFAULT_LANGUAGE
    text = text.replace("_", "-")
    lower = text.lower()
    aliases = {
        "en-us": "en",
        "en-gb": "en",
        "es-es": "es",
        "es-mx": "es",
        "fr-fr": "fr",
        "de-de": "de",
        "it-it": "it",
        "pt": "pt-BR",
        "pt-br": "pt-BR",
        "nl-nl": "nl",
        "pl-pl": "pl",
        "ja-jp": "ja",
        "ko-kr": "ko",
        "zh": "zh-Hans",
        "zh-cn": "zh-Hans",
        "zh-sg": "zh-Hans",
        "zh-hans": "zh-Hans",
    }
    if lower in aliases:
        return aliases[lower]
    if text in _SUPPORTED_CODES:
        return text
    base = lower.split("-", 1)[0]
    for language in SUPPORTED_LANGUAGES:
        if language.code.lower() == base:
            return language.code
    return DEFAULT_LANGUAGE


