def tr(message_id, language_code=None, **kwargs):
    language = normalize_language_code(language_code)
    translations = MESSAGES.get(message_id, {})
    template = translations.get(language) or translations.get(DEFAULT_LANGUAGE) or message_id
    try:
        return template.format(**kwargs)
    except (KeyError, IndexError, ValueError):
        return template


def _format_image_label(prefix, language):
    prefix = str(prefix or "").strip()
    templates = {
        "en": "{prefix} image",
        "es": "Imagen {prefix}",
        "fr": "Image {prefix}",
        "de": "{prefix}-Image",
        "it": "Immagine {prefix}",
        "pt-BR": "Imagem {prefix}",
        "nl": "{prefix}-image",
        "pl": "Obraz {prefix}",
        "ja": "{prefix} イメージ",
        "ko": "{prefix} 이미지",
        "zh-Hans": "{prefix} 映像",
    }
    template = templates.get(language) or templates[DEFAULT_LANGUAGE]
    return template.format(prefix=prefix)


def _format_raw_sector_image_label(prefix, language):
    prefix = str(prefix or "").strip()
    templates = {
        "en": "{prefix} raw sector image",
        "es": "Imagen {prefix} de sectores sin procesar",
        "fr": "Image {prefix} de secteurs bruts",
        "de": "{prefix}-Rohsektor-Image",
        "it": "Immagine {prefix} settori grezzi",
        "pt-BR": "Imagem {prefix} de setores brutos",
        "nl": "{prefix} ruwe-sectorimage",
        "pl": "Obraz {prefix} surowych sektorów",
        "ja": "{prefix} 生セクターイメージ",
        "ko": "{prefix} 원시 섹터 이미지",
        "zh-Hans": "{prefix} 原始扇区映像",
    }
    template = templates.get(language) or templates[DEFAULT_LANGUAGE]
    return template.format(prefix=prefix)


def translate_text(text, language_code=None, **kwargs):
    source = str(text or "")
    message_id = TEXT_TO_MESSAGE_ID.get(source)
    if message_id:
        return tr(message_id, language_code, **kwargs)
    language = normalize_language_code(language_code)
    translations = COMMON_TEXT_TRANSLATIONS.get(source)
    if translations:
        return translations.get(language) or source
    if source.endswith("..."):
        base = source[:-3]
        translations = COMMON_TEXT_TRANSLATIONS.get(base)
        if translations:
            return f"{translations.get(language) or base}..."
    if source.endswith(":"):
        base = source[:-1]
        translations = COMMON_TEXT_TRANSLATIONS.get(base)
        if translations:
            return f"{translations.get(language) or base}:"
    if source.endswith(" raw sector image"):
        prefix = source[: -len(" raw sector image")]
        return _format_raw_sector_image_label(prefix, language)
    if source.endswith(" image"):
        prefix = source[: -len(" image")]
        return _format_image_label(prefix, language)
    return source


def guidance_for_error_detail(detail, language_code=None):
    text = str(detail or "")
    lower = text.lower()
    if not text:
        return ""
    if "cancelled" in lower or "canceled" in lower:
        return tr("guidance.cancelled", language_code)
    if "mtools" in lower or any(command in lower for command in ("mformat", "mcopy", "mdir", "mdel", "mren")):
        return tr("guidance.mtools_missing", language_code)
    if "greaseweazle cli" in lower or ("greaseweazle" in lower and "not found" in lower):
        return tr("guidance.greaseweazle_missing", language_code)
    if (
        "not recognized as an internal or external command" in lower
        or "no such file or directory" in lower
        or "command not found" in lower
    ):
        return tr("guidance.command_missing", language_code)
    if "access is denied" in lower and ("physicaldrive" in lower or "winerror 5" in lower or "\\\\.\\" in lower):
        return tr("guidance.windows_device_access", language_code)
    if "permission denied" in lower or "access is denied" in lower or "operation not permitted" in lower:
        return tr("guidance.permission_denied", language_code)
    if "device or resource busy" in lower or "text file busy" in lower or "could not lock" in lower:
        return tr("guidance.device_busy", language_code)
    if "write protected" in lower or "write-protected" in lower or "read-only file system" in lower:
        return tr("guidance.write_protected", language_code)
    if "disk full" in lower or "no directory slots" in lower or "too large to fit" in lower:
        return tr("guidance.disk_full", language_code)
    if "already exists" in lower:
        return tr("guidance.already_exists", language_code)
    if "unsupported image" in lower or "unsupported output image" in lower:
        return tr("guidance.unsupported_image", language_code)
    if "fat12" in lower or "boot sector" in lower:
        return tr("guidance.fat12_boot_sector", language_code)
    if "unreadable" in lower or "missing sectors" in lower or ("sector" in lower and "greaseweazle" in lower):
        return tr("guidance.greaseweazle_sector_failures", language_code)
    if "greaseweazle" in lower:
        return tr("guidance.greaseweazle_sector_failures", language_code)
    return ""
